      the entities graph. When you need sensor metadata beyond the IRI, check
      the endpoint graph inventory for the entities graph.

SPARQL Examples (7):
  "List recent observations" -> http://localhost:8080/sparql
    Returns all sosa:Observation instances with result value and timestamp, ordered newest first.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT ?obs ?result ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:hasSimpleResult ?result ;
             sosa:resultTime ?time .
      }
    }
    ORDER BY DESC(?time)
    LIMIT 10
  "Observations by sensor" -> http://localhost:8080/sparql
    Returns observations made by a specific sensor. Bind ?sensor to a sosa:Sensor IRI.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT ?obs ?result ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:madeBySensor ?sensor ;
             sosa:hasSimpleResult ?result ;
             sosa:resultTime ?time .
      }
    }
    ORDER BY DESC(?time)
  "Discover sensors" -> http://localhost:8080/sparql
    Returns all distinct sensors that have recorded observations at this node.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT DISTINCT ?sensor WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:madeBySensor ?sensor .
      }
    }
  "Entity lookup by IRI" -> http://localhost:8080/sparql
    Returns all properties and values for an entity. Replace {entity_iri} with the full entity IRI from the node entity namespace.
    SELECT ?p ?o WHERE {
      GRAPH ?g {
        <{entity_iri}> ?p ?o .
      }
    }
  "Observations with SIO measurements" -> http://localhost:8080/sparql
    Returns observations where the result is encoded via the SIO measurement chain: sio:has-attribute -> sio:MeasuredValue -> sio:has-value. Use this when sosa:hasSimpleResult returns empty.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    PREFIX sio:  <http://semanticscience.org/resource/>
    SELECT ?obs ?value ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:resultTime ?time ;
             sio:has-attribute ?mv .
        ?mv a sio:MeasuredValue ;
            sio:has-value ?value .
      }
    }
    ORDER BY DESC(?time)
    LIMIT 10
  "SIO measurements with units" -> http://localhost:8080/sparql
    Returns SIO measurement chains including the unit label. Traverses: Observation -> sio:has-attribute -> MeasuredValue -> sio:has-unit -> rdfs:label.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    PREFIX sio:  <http://semanticscience.org/resource/>
    PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
    SELECT ?obs ?value ?unit ?time WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation ;
             sosa:resultTime ?time ;
             sio:has-attribute ?mv .
        ?mv a sio:MeasuredValue ;
            sio:has-value ?value .
        OPTIONAL { ?mv sio:has-unit ?u . ?u rdfs:label ?unit . }
      }
    }
    ORDER BY DESC(?time)
    LIMIT 10
  "Count observations" -> http://localhost:8080/sparql
    Returns the total number of observations stored at this node.
    PREFIX sosa: <http://www.w3.org/ns/sosa/>
    SELECT (COUNT(?obs) AS ?total) WHERE {
      GRAPH <http://localhost:8080/graph/observations> {
        ?obs a sosa:Observation .
      }
    }

External SPARQL Services (3):
  Use query_external_sparql(endpoint_url, query) to query these.

  QLever Wikidata SPARQL Endpoint
    URL: https://qlever.cs.uni-freiburg.de/api/wikidata
    Description: Wikidata via QLever — universities, research institutions, cities, organizations. Use for institutional context and geographic enrichment (D20 SDL use case).
    Vocabularies: http://www.wikidata.org/ontology#, http://schema.org/, http://www.wikidata.org/prop/direct/
    Example: "Lookup entity by Wikidata QID"
      PREFIX wdt: <http://www.wikidata.org/prop/direct/>
      PREFIX wd:  <http://www.wikidata.org/entity/>
      PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
      PREFIX schema: <http://schema.org/>
      SELECT ?label ?description ?instanceOf WHERE {
        wd:Q178848 rdfs:label ?label ;
                   schema:description ?description ;
                   wdt:P31 ?instanceOf .
        FILTER(LANG(?label) = "en")
        FILTER(LANG(?description) = "en")
      } LIMIT 5
    Example: "Lookup university location by name"
      PREFIX wdt: <http://www.wikidata.org/prop/direct/>
      PREFIX wd:  <http://www.wikidata.org/entity/>
      PREFIX rdfs: <http://www.w3.org/2000/01/rdf-schema#>
      PREFIX schema: <http://schema.org/>
      SELECT ?item ?label ?description ?cityLabel WHERE {
        ?item rdfs:label ?label ;
              schema:description ?description ;
              wdt:P31 wd:Q3918 ;
              wdt:P131 ?city .
        ?city rdfs:label ?cityLabel .
        FILTER(LANG(?label) = "en")
        FILTER(LANG(?description) = "en")
        FILTER(LANG(?cityLabel) = "en")
        FILTER(CONTAINS(LCASE(?label), "notre dame"))
      } LIMIT 5

  QLever OpenStreetMap SPARQL Endpoint
    URL: https://qlever.cs.uni-freiburg.de/api/osm-planet
    Description: OpenStreetMap via QLever — geographic features, research facilities, laboratories, institutions. Use for geographic context of observation locations (D20 SDL use case).
    Vocabularies: https://www.openstreetmap.org/wiki/Key:
    Example: "Lookup facility by name substring"
      PREFIX osmkey: <https://www.openstreetmap.org/wiki/Key:>
      SELECT ?place ?name ?type WHERE {
        ?place osmkey:name ?name .
        OPTIONAL { ?place osmkey:amenity ?type }
        FILTER(CONTAINS(LCASE(?name), "notre dame"))
      } LIMIT 10
    Example: "Find research facilities near coordinates"
      PREFIX geo: <http://www.opengis.net/ont/geosparql#>
      PREFIX osmkey: <https://www.openstreetmap.org/wiki/Key:>
      PREFIX osmrel: <https://osm2rdf.cs.uni-freiburg.de/rdf/relation#>
      SELECT ?place ?name ?amenity WHERE {
        ?place osmkey:amenity ?amenity ;
               osmkey:name ?name .
        FILTER(?amenity IN ("laboratory", "research_institute", "university"))
      } LIMIT 10

  QLever PubChem SPARQL Endpoint
    URL: https://qlever.cs.uni-freiburg.de/api/pubchem
    Description: PubChem RDF via QLever — chemical compounds, CIDs, molecular properties, InChI/SMILES, bioassays. Use for reagent/analyte enrichment in SDL observation data (D20).
    Vocabularies: http://rdf.ncbi.nlm.nih.gov/pubchem/vocabulary, http://semanticscience.org/resource/
    Example: "Get compound properties by CID"
      PREFIX sio: <http://semanticscience.org/resource/>
      PREFIX dct: <http://purl.org/dc/terms/>
      SELECT ?attrType ?val WHERE {
        <http://rdf.ncbi.nlm.nih.gov/pubchem/compound/CID2244> sio:SIO_000008 ?attr .
        ?attr a ?attrType ; sio:SIO_000300 ?val .
      } LIMIT 20
    Example: "Lookup molecular formula by CID"
      PREFIX sio: <http://semanticscience.org/resource/>
      SELECT ?formula WHERE {
        <http://rdf.ncbi.nlm.nih.gov/pubchem/compound/CID2244> sio:SIO_000008 ?attr .
        ?attr a sio:CHEMINF_000335 ; sio:SIO_000300 ?formula .
      } LIMIT 5

